// multicamShotCropName resolves a crop ID to its display name.
func multicamShotCropName(cropID string, clipCrops crops.CropArray) string {
	for _, c := range clipCrops {
		if c.ID == cropID {
			if c.Name != "" {
				return c.Name
			}
			return c.AspectRatio + " Crop"
		}
	}
	return "Unknown"
}

